<?php

class SurroundedRegions
{

    public $grid;

    public $visited = [];

    public $color_nodes = [];

    public $is_having_edges = false;
    
    public $directions = [[-1, 0], [1, 0], [0, -1], [0, 1]];

    public $rLength;

    public $cLength;


    /**
     * @param String[][] $board
     * @return NULL
     */
    function solve(&$board)
    {


        $this->grid = $board;
        $this->visited = [];

        if(!$this->grid) {
            return 0;
        }


        $this->rLength = count($this->grid);
        $this->cLength = count($this->grid[0]);


        for($r = 0; $r < $this->rLength; $r++) {
            for($c = 0; $c < $this->cLength; $c++) {
                
                    if(($r === 0 || 
                        $c === 0 ||
                        $r === ($this->rLength - 1) ||
                        $c === ($this->cLength - 1)
                        ) &&
                        $this->grid[$r][$c] === "O"
                    ) {
                        continue;
                    }
                    
                    $this->visited = [];
                    $this->color_nodes = [];
                    $this->is_having_edges = false;

                    if(!isset($this->visited["$r+$c"]) && $this->grid[$r][$c] === "O") {
                        $is_having_edges = $this->dfs($r, $c);
                        # color visited nodes without having edges
                        #echo "r: $r, c: $c \n";
                        #echo "is_having_edges: $is_having_edges \n";
                        if(!$this->is_having_edges) {
                            #echo "color_nodes: \n";
                            #var_dump($this->color_nodes);
                            foreach($this->color_nodes as [$node_r, $node_c]) {
                                $this->grid[$node_r][$node_c] = "X";
                            }
                        }
                    }
                
                
            }
        }

        $board = $this->grid;

        return $board;
    }

    public function dfs($r, $c)
    {

        $this->visited["$r+$c"] = true;
        $this->color_nodes[]    = [$r, $c];
        $this->is_having_edges  = false;        

        #echo "r: $r, c: $c \n";
        #echo "visited: \n";
        #var_dump($this->visited);

        #echo "color nodes: \n";
        #var_dump($this->color_nodes);

        foreach($this->directions as [$dx, $dy]) {

            $next_r = $r + $dx;
            $next_c = $c + $dy;

            #echo "84----dfs visiting next_r next_c(r: $r, c: $c): $next_r+$next_c \n";

            if(0 <= $next_r && $next_r < $this->rLength && 0 <= $next_c && $next_c < $this->cLength && $this->grid[$next_r][$next_c] === "O") {

                if(($next_r  === 0 ||
                    $next_c === 0 ||
                    $next_r === ($this->rLength - 1) ||
                    $next_c === ($this->cLength - 1)) && 
                    $this->grid[$next_r][$next_c] === "O"
                ) {

                    $this->is_having_edges = true;              
                    #echo "96 next_r  next_c $next_r $next_c(r:$r, c:$c) | is_having_edges: $this->is_having_edges \n";

                    break;
                }

                if (!isset($this->visited["$next_r+$next_c"])) { 
                    
                    #echo "103------dfs visiting next_r next_c: $next_r+$next_c \n";
                    $this->visited["$next_r+$next_c"] = true;
                    $is_having_edges = $this->dfs($next_r, $next_c);

                    if($is_having_edges) {                        
                        break;                        
                    } else {
                        $this->color_nodes[] = [$next_r, $next_c];
                    }
                    
                    # reset visited on backtrack returning
                    #unset($this->visited["$next_r+$next_c"]);
                    #gc_collect_cycles(); # unsetting items in a long loop, manually trigger the garbage collector to reclaim memory immediately
                    #echo "visited backtrack: \n";   
                    #var_dump($this->visited);
                }
            }
        }


        # reset visited for each cell
        #unset($this->visited["$r+$c"]);
        #gc_collect_cycles(); # unsetting items in a long loop, manually trigger the garbage collector to reclaim memory immediately

        return $this->is_having_edges;
    }
}


